import{_ as a,o as r,c as s,ae as n}from"./chunks/framework.B6gjLfeO.js";const p=JSON.parse('{"title":"Currency Support for Analysis Dashboards","description":"","frontmatter":{"title":"Currency Support for Analysis Dashboards","slug":"currency-support-for-analysis-dashboards"},"headers":[],"relativePath":"account-hub/currency-support-for-analysis-dashboards.md","filePath":"account-hub/currency-support-for-analysis-dashboards.md"}'),o={name:"account-hub/currency-support-for-analysis-dashboards.md"};function t(i,e,c,l,d,u){return r(),s("div",null,[...e[0]||(e[0]=[n('<p>Branch has added currency configuration capabilities to Analysis Dashboards, giving you the flexibility to view your revenue and cost metrics in your preferred currency for better regional analysis and reporting.</p><h2 id="what-s-new" tabindex="-1">What’s new? <a class="header-anchor" href="#what-s-new" aria-label="Permalink to &quot;What’s new?&quot;">​</a></h2><p>Analysis Dashboards now include the following currency functionality:</p><ul><li><strong>Dashboard-level currency</strong>: Set a default currency parameter that applies across all widgets on your dashboard containing currency-related measures.</li><li><strong>Widget-level currency</strong>: Override the dashboard currency for individual widgets, allowing you to compare performance across different currencies on the same dashboard.</li><li><strong>Comprehensive currency support</strong>: Choose from a list of over 30 currencies to match your business needs and regional reporting requirements.</li></ul><h2 id="benefits" tabindex="-1">Benefits <a class="header-anchor" href="#benefits" aria-label="Permalink to &quot;Benefits&quot;">​</a></h2><p>Currency configuration enables you to:</p><ul><li>View campaign performance in the currencies most relevant to your regional teams and stakeholders.</li><li>Maintain a single currency standard across your dashboard for clearer performance comparisons.</li><li>Create duplicate dashboards with different currency settings when you need to analyze performance across multiple markets simultaneously.</li></ul><h2 id="access" tabindex="-1">Access <a class="header-anchor" href="#access" aria-label="Permalink to &quot;Access&quot;">​</a></h2><p>Currency configuration support is available to all Analysis Dashboard users.</p><p>Analysis Dashboards represent the next evolution in Branch&#39;s marketing analytics and reporting. They unify data from ads, social media, SEO, email, and more into a single, cohesive experience.</p><p>Access to this feature is currently being rolled out to customers in phases as part of Branch&#39;s new platform experience.</p><h2 id="learn-more" tabindex="-1">Learn more <a class="header-anchor" href="#learn-more" aria-label="Permalink to &quot;Learn more&quot;">​</a></h2><p>For detailed instructions on configuring currency at both the dashboard and widget levels, visit our dedicated <a href="./analysis-dashboards.html#configure-dashboard-currency">Analysis Dashboards guide.</a></p>',13)])])}const y=a(o,[["render",t]]);export{p as __pageData,y as default};
